def range_summary(nums):
    if not nums:
        return ''

    sorted_nums = sorted(set(nums))
    ranges = []
    start = sorted_nums[0]

    for i in range(1, len(sorted_nums)):
        if sorted_nums[i] != sorted_nums[i-1] + 1:
            if start == sorted_nums[i-1]:
                ranges.append(str(start))
            else:
                ranges.append(f"{start}-{sorted_nums[i-1]}")
            start = sorted_nums[i]

    # Handle the last range
    if start == sorted_nums[-1]:
        ranges.append(str(start))
    else:
        ranges.append(f"{start}-{sorted_nums[-1]}")

    return ','.join(ranges)
